"""Map background tiles (b490): 96x96 WebP room tiles keyed by CSS class.

Sliced from the hand-painted 8x8 room-tile sheet (sprite_package/
source_sheets/room_tiles_sheet.png). Floor tiles are chosen by an
opening MASK -- which cardinal neighbours of the cell are open
(N=1 E=2 S=4 W=8) -- so every room's drawn entrances line up with the
actual passages on the floor. Missing direction-combinations are
synthesized by rotating base tiles a quarter turn; the four 2-opening
corner masks fall back to their nearest superset (an extra painted
opening is harmless; a missing one would hide a real passage).
Themed tiles (chest, altar, library...) are used as-is per room type.

Generated by scratchpad build script -- regenerate rather than edit.
"""

FLOOR_VARIANTS = {0: ['mtf1a', 'mtf1b', 'mtf1c'], 1: ['mtf1a', 'mtf1b', 'mtf1c'], 2: ['mtf2a'], 3: ['mtf7a', 'mtf7b'], 4: ['mtf4a'], 5: ['mtf5a', 'mtf5b'], 6: ['mtfEa', 'mtfEb', 'mtfEc'], 7: ['mtf7a', 'mtf7b'], 8: ['mtf8a'], 9: ['mtfDa', 'mtfDb'], 10: ['mtfAa', 'mtfAb'], 11: ['mtfBa', 'mtfBb', 'mtfBc'], 12: ['mtfEa', 'mtfEb', 'mtfEc'], 13: ['mtfDa', 'mtfDb'], 14: ['mtfEa', 'mtfEb', 'mtfEc'], 15: ['mtfFa', 'mtfFb', 'mtfFc']}

THEMED_TILE_CLASSES = {'C': 'mtrC', 'P': 'mtrP', 'A': 'mtrA', 'L': 'mtrL', 'T': 'mtrT', 'G': 'mtrG', 'O': 'mtrO', 'B': 'mtrB', 'F': 'mtrF', 'Q': 'mtrQ', 'K': 'mtrK', 'N': 'mtrN', 'V': 'mtrV', 'U': 'mtrU', 'D': 'mtrD', 'W': 'mtrW', 'Z': 'mtrZ'}

TILE_B64 = {
    'mtf1a': '',
    'mtf1b': '',
    'mtf1c': '',
    'mtfBa': '',
    'mtfAa': '',
    'mtfAb': '',
    'mtfFa': '',
    'mtfFb': '',
    'mtfEa': '',
    'mtfEb': '',
    'mtfEc': '',
    'mtfFc': '',
    'mtfBb': '',
    'mtfBc': '',
    'mtf2a': '',
    'mtf4a': '',
    'mtf8a': '',
    'mtf5a': '',
    'mtf5b': '',
    'mtf7a': '',
    'mtf7b': '',
    'mtfDa': '',
    'mtfDb': '',
    'mtrC': '',
    'mtrP': '',
    'mtrA': '',
    'mtrL': '',
    'mtrT': '',
    'mtrG': '',
    'mtrO': '',
    'mtrB': '',
    'mtrF': '',
    'mtrQ': '',
    'mtrK': '',
    'mtrN': '',
    'mtrV': '',
    'mtrU': '',
    'mtrD': '',
    'mtrW': '',
    'mtrZ': '',
}


def floor_tile_class(mask, x, y):
    """Deterministic variant pick so the floor looks varied but stable."""
    variants = FLOOR_VARIANTS.get(mask) or FLOOR_VARIANTS[1]
    return variants[(x * 7 + y * 13) % len(variants)]


def map_tiles_css():
    """CSS block defining every tile class. Injected ONCE into the HTML
    shell (wrap_html) so per-move render payloads stay tiny -- cells only
    carry a class name."""
    rules = [
        ".zmap-cell.mt { background-size: 100% 100%; "
        "image-rendering: pixelated; border-radius: 3px; }"
    ]
    for cls, b64 in TILE_B64.items():
        rules.append(
            f".zmap-cell.{cls} {{ background-image: "
            f"url(data:image/webp;base64,{b64}); }}"
        )
    return "\n".join(rules)
